 11→      type: 'paren';
 12→      value: '(' | ')';
 13→    }
 14→  | {
 15→      type: 'func';
 16→      value: string;
 17→    };
 18→
 19→const FUNCTIONS: Record<string, (n: number) => number> = {
 20→  sqrt: Math.sqrt,
 21→  abs: Math.abs,
 22→  sin: Math.sin,
 23→  cos: Math.cos,
 24→  tan: Math.tan,
 25→  log: Math.log10,
 26→  ln: Math.log,
 27→  ceil: Math.ceil,
 28→  floor: Math.floor,
 29→  round: Math.round,
 30→  exp: Math.exp,
 31→};
 32→
 33→const CONSTANTS: Record<string, number> = {
 34→  pi: Math.PI,
 35→  e: Math.E,
 36→};
 37→
 38→function tokenize(input: string): Token[] | null {
 39→  const tokens: Token[] = [];
 40→  let i = 0;
 41→  const s = input.replace(/\s+/g, '');
 42→
 43→  while (i < s.length) {
 44→    const ch = s[i]!;
 45→
 46→    if ((ch >= '0' && ch <= '9') || ch === '.') {
 47→      let num = '';
 48→      while (i < s.length && ((s[i]! >= '0' && s[i]! <= '9') || s[i] === '.')) {
 49→        num += s[i];
 50→        i++;
 51→      }
 52→      const parsed = parseFloat(num);
 53→      if (isNaN(parsed)) return null;
 54→      tokens.push({
 55→        type: 'number',
 56→        value: parsed,
 57→      });
 58→      continue;
 59→    }
 60→
 61→    if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z')) {
 62→      let word = '';
 63→      while (
 64→        i < s.length &&
 65→        ((s[i]! >= 'a' && s[i]! <= 'z') || (s[i]! >= 'A' && s[i]! <= 'Z'))
 66→      ) {
 67→        word += s[i];
 68→        i++;
 69→      }
 70→      const lower = word.toLowerCase();
 71→      if (CONSTANTS[lower] !== undefined) {
 72→        tokens.push({
 73→          type: 'number',
 74→          value: CONSTANTS[lower],
 75→        });
 76→      } else if (FUNCTIONS[lower]) {
 77→        tokens.push({
 78→          type: 'func',
 79→          value: lower,
 80→        });
 81→      } else {
 82→        return null;
 83→      }
 84→      continue;
 85→    }
 86→
 87→    if (ch === '(' || ch === ')') {
 88→      tokens.push({
 89→        type: 'paren',
 90→        value: ch,
 91→      });
 92→      i++;
 93→      continue;
 94→    }
 95→
 96→    if (ch === '+' || ch === '-' || ch === '*' || ch === '/' || ch === '^') {
 97→      tokens.push({
 98→        type: 'op',
 99→        value: ch,
100→      });
101→      i++;
102→      continue;
103→    }
104→
105→    if (ch === '%') {
106→      tokens.push({
107→        type: 'op',
108→        value: '%',
109→      });
